namespace sv_04652b5642614c9b9246d8a50d24a047.Services;

public record Channel(int Id, string Name, string Description, int UnreadCount);
public record Message(int Id, int ChannelId, string Author, string Content, DateTime SentAt, int? ReplyToId, List<Reaction> Reactions);
public record Reaction(string Emoji, List<string> Users);
public record ThreadSummary(int RootMessageId, int ReplyCount, DateTime LastReplyAt);

public interface IChatService
{
    Task<List<Channel>> GetChannelsAsync();
    Task<List<Message>> GetMessagesAsync(int channelId, int skip, int take);
    Task<Message> SendMessageAsync(int channelId, string content, int? replyToId);
    Task<List<Message>> GetThreadAsync(int rootMessageId);
    Task AddReactionAsync(int messageId, string emoji);
    Task MarkChannelReadAsync(int channelId);
}

@* Popup with common emoji reactions *@

<div class="emoji-picker">
    @foreach (var emoji in _emojis)
    {
        <button class="emoji-btn" @onclick="() => OnEmojiSelected.InvokeAsync(emoji)" @onclick:stopPropagation>
            @emoji
        </button>
    }
</div>

@code {
    [Parameter, EditorRequired]
    public EventCallback<string> OnEmojiSelected { get; set; }

    private static readonly string[] _emojis = ["👍", "❤️", "😂", "🎉", "😮", "👎"];
}

.emoji-picker {
    display: flex;
    gap: 2px;
    padding: 4px 6px;
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 6px;
    box-shadow: 0 2px 8px rgba(0, 0, 0, 0.15);
    position: absolute;
    top: -40px;
    right: 0;
    z-index: 10;
}

.emoji-btn {
    background: none;
    border: none;
    font-size: 1.1rem;
    padding: 2px 4px;
    cursor: pointer;
    border-radius: 4px;
    line-height: 1;
}

.emoji-btn:hover {
    background: #f0f0f0;
}

@* Reusable message/reply input — used in main area and thread panel *@

<div class="message-input-area">
    <textarea class="form-control message-textarea"
              @bind="content"
              @bind:event="oninput"
              @onkeydown="HandleKeyDown"
              placeholder="@Placeholder"
              rows="2"></textarea>
    <button class="btn btn-primary send-btn"
            @onclick="Send"
            disabled="@string.IsNullOrWhiteSpace(content)">
        @ButtonText
    </button>
</div>

@code {
    [Parameter] public string Placeholder { get; set; } = "Type a message...";
    [Parameter] public string ButtonText { get; set; } = "Send";
    [Parameter, EditorRequired] public EventCallback<string> OnSend { get; set; }

    private string content = "";

    private async Task Send()
    {
        if (string.IsNullOrWhiteSpace(content)) return;
        var text = content.Trim();
        content = "";
        await OnSend.InvokeAsync(text);
    }

    private async Task HandleKeyDown(KeyboardEventArgs e)
    {
        if (e.Key == "Enter" && !e.ShiftKey)
        {
            await Send();
        }
    }
}

.message-input-area {
    display: flex;
    gap: 8px;
    padding: 12px 16px;
    border-top: 1px solid #dee2e6;
    background: #fff;
    align-items: flex-end;
}

.message-textarea {
    flex: 1;
    resize: none;
    font-size: 0.9rem;
}

.send-btn {
    align-self: flex-end;
    white-space: nowrap;
}

@* Single message with reactions, hover actions, and thread link *@

<div class="message-item" @onmouseenter="ShowActions" @onmouseleave="HideActions">
    <div class="message-header">
        <span class="message-author">@Message.Author</span>
        <span class="message-time">@FormatRelativeTime(Message.SentAt)</span>
    </div>
    <div class="message-content">@Message.Content</div>

    @if (Message.Reactions.Count > 0)
    {
        <div class="message-reactions">
            @foreach (var reaction in Message.Reactions)
            {
                <span class="reaction-badge" @onclick="() => OnReactionAdded.InvokeAsync((Message.Id, reaction.Emoji))">
                    @reaction.Emoji @reaction.Users.Count
                </span>
            }
        </div>
    }

    @if (ReplyCount > 0)
    {
        <button class="thread-link" @onclick="() => OnReplyClicked.InvokeAsync(Message.Id)">
            💬 @ReplyCount @(ReplyCount == 1 ? "reply" : "replies")
        </button>
    }

    @if (_showActions)
    {
        <div class="message-actions">
            <button class="action-btn" @onclick="() => OnReplyClicked.InvokeAsync(Message.Id)" title="Reply in thread">
                💬 Reply
            </button>
            <button class="action-btn" @onclick="ToggleEmojiPicker" title="Add reaction">
                😊 React
            </button>
        </div>

        @if (_showEmojiPicker)
        {
            <EmojiPicker OnEmojiSelected="HandleEmojiSelected" />
        }
    }
</div>

@code {
    [Parameter, EditorRequired] public Message Message { get; set; } = default!;
    [Parameter] public int ReplyCount { get; set; }
    [Parameter] public EventCallback<int> OnReplyClicked { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReactionAdded { get; set; }

    private bool _showActions;
    private bool _showEmojiPicker;

    private void ShowActions() => _showActions = true;

    private void HideActions()
    {
        _showActions = false;
        _showEmojiPicker = false;
    }

    private void ToggleEmojiPicker() => _showEmojiPicker = !_showEmojiPicker;

    private async Task HandleEmojiSelected(string emoji)
    {
        _showEmojiPicker = false;
        await OnReactionAdded.InvokeAsync((Message.Id, emoji));
    }

    private static string FormatRelativeTime(DateTime sentAt)
    {
        var diff = DateTime.UtcNow - sentAt;
        if (diff.TotalSeconds < 30) return "just now";
        if (diff.TotalMinutes < 1) return $"{(int)diff.TotalSeconds}s ago";
        if (diff.TotalMinutes < 60) return $"{(int)diff.TotalMinutes} min ago";
        if (diff.TotalHours < 24) return $"{(int)diff.TotalHours}h ago";
        if (diff.TotalDays < 7) return $"{(int)diff.TotalDays}d ago";
        return sentAt.ToString("MMM d, yyyy");
    }
}

.message-item {
    position: relative;
    padding: 6px 16px;
    border-radius: 4px;
    transition: background 0.1s;
}

.message-item:hover {
    background: #f8f9fa;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.message-author {
    font-weight: 700;
    font-size: 0.9rem;
}

.message-time {
    font-size: 0.75rem;
    color: #6c757d;
}

.message-content {
    font-size: 0.9rem;
    line-height: 1.5;
    white-space: pre-wrap;
    word-break: break-word;
}

.message-reactions {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 4px;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 3px;
    padding: 2px 8px;
    font-size: 0.8rem;
    background: #e9ecef;
    border: 1px solid #dee2e6;
    border-radius: 12px;
    cursor: pointer;
    user-select: none;
}

.reaction-badge:hover {
    background: #dee2e6;
}

.thread-link {
    display: inline-block;
    margin-top: 4px;
    padding: 2px 0;
    font-size: 0.8rem;
    color: #0d6efd;
    background: none;
    border: none;
    cursor: pointer;
}

.thread-link:hover {
    text-decoration: underline;
}

.message-actions {
    position: absolute;
    top: -4px;
    right: 8px;
    display: flex;
    gap: 2px;
    padding: 2px 4px;
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 6px;
    box-shadow: 0 1px 4px rgba(0, 0, 0, 0.1);
    z-index: 5;
}

.action-btn {
    background: none;
    border: none;
    font-size: 0.78rem;
    padding: 3px 8px;
    cursor: pointer;
    border-radius: 4px;
    white-space: nowrap;
}

.action-btn:hover {
    background: #f0f0f0;
}

