.message-item {
    position: relative;
    padding: 6px 16px;
    border-radius: 4px;
    transition: background 0.1s;
}

.message-item:hover {
    background: #f8f9fa;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
    margin-bottom: 2px;
}

.message-author {
    font-weight: 700;
    font-size: 0.9rem;
}

.message-time {
    font-size: 0.75rem;
    color: #6c757d;
}

.message-content {
    font-size: 0.9rem;
    line-height: 1.5;
    white-space: pre-wrap;
    word-break: break-word;
}

.message-reactions {
    display: flex;
    flex-wrap: wrap;
    gap: 4px;
    margin-top: 4px;
}

.reaction-badge {
    display: inline-flex;
    align-items: center;
    gap: 3px;
    padding: 2px 8px;
    font-size: 0.8rem;
    background: #e9ecef;
    border: 1px solid #dee2e6;
    border-radius: 12px;
    cursor: pointer;
    user-select: none;
}

.reaction-badge:hover {
    background: #dee2e6;
}

.thread-link {
    display: inline-block;
    margin-top: 4px;
    padding: 2px 0;
    font-size: 0.8rem;
    color: #0d6efd;
    background: none;
    border: none;
    cursor: pointer;
}

.thread-link:hover {
    text-decoration: underline;
}

.message-actions {
    position: absolute;
    top: -4px;
    right: 8px;
    display: flex;
    gap: 2px;
    padding: 2px 4px;
    background: #fff;
    border: 1px solid #dee2e6;
    border-radius: 6px;
    box-shadow: 0 1px 4px rgba(0, 0, 0, 0.1);
    z-index: 5;
}

.action-btn {
    background: none;
    border: none;
    font-size: 0.78rem;
    padding: 3px 8px;
    cursor: pointer;
    border-radius: 4px;
    white-space: nowrap;
}

.action-btn:hover {
    background: #f0f0f0;
}

