arguments.file_text:
@* Scrollable message list with load-older pagination *@

<div class="message-list">
    @if (HasMore)
    {
        <div class="load-older">
            <button class="btn btn-sm btn-outline-secondary"
                    @onclick="OnLoadOlder"
                    disabled="@IsLoading">
                @(IsLoading ? "Loading..." : "↑ Load older messages")
            </button>
        </div>
    }

    @foreach (var message in Messages)
    {
        var msgId = message.Id;
        ThreadSummaries.TryGetValue(msgId, out var summary);
        var replyCount = summary?.ReplyCount ?? 0;

        <MessageItem Message="message"
                     ReplyCount="replyCount"
                     OnReplyClicked="OnReplyClicked"
                     OnReactionAdded="OnReactionAdded" />
    }

    @if (Messages.Count == 0 && !IsLoading)
    {
        <div class="no-messages">No messages yet. Start the conversation!</div>
    }
</div>

@code {
    [Parameter] public List<Message> Messages { get; set; } = new();
    [Parameter] public Dictionary<int, ThreadSummary> ThreadSummaries { get; set; } = new();
    [Parameter] public bool HasMore { get; set; }
    [Parameter] public bool IsLoading { get; set; }
    [Parameter] public EventCallback<int> OnReplyClicked { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReactionAdded { get; set; }
    [Parameter] public EventCallback OnLoadOlder { get; set; }
}

.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 8px 0;
    display: flex;
    flex-direction: column;
}

.load-older {
    text-align: center;
    padding: 8px;
}

.no-messages {
    flex: 1;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #6c757d;
    font-size: 0.95rem;
}

@* Single channel row in the sidebar *@

<div class="channel-item @(IsActive ? "active" : "")" @onclick="OnClick">
    <div class="channel-top-row">
        <span class="channel-name"># @Channel.Name</span>
        @if (Channel.UnreadCount > 0)
        {
            <span class="unread-badge">@Channel.UnreadCount</span>
        }
    </div>
    @if (!string.IsNullOrWhiteSpace(Channel.Description))
    {
        <div class="channel-desc">@TruncateDescription(Channel.Description)</div>
    }
</div>

@code {
    [Parameter, EditorRequired] public Channel Channel { get; set; } = default!;
    [Parameter] public bool IsActive { get; set; }
    [Parameter] public EventCallback OnClick { get; set; }

    private static string TruncateDescription(string desc)
        => desc.Length > 40 ? desc[..40] + "…" : desc;
}

.channel-item {
    padding: 8px 14px;
    cursor: pointer;
    border-left: 3px solid transparent;
    transition: background 0.15s;
}

.channel-item:hover {
    background: rgba(255, 255, 255, 0.08);
}

.channel-item.active {
    background: rgba(255, 255, 255, 0.12);
    border-left-color: #fff;
}

.channel-top-row {
    display: flex;
    justify-content: space-between;
    align-items: center;
}

.channel-name {
    font-weight: 600;
    font-size: 0.9rem;
    color: #e0e0e0;
}

.channel-item.active .channel-name {
    color: #fff;
}

