+@* Scrollable message list with load-older pagination *@
+
+<div class="message-list">
+    @if (HasMore)
+    {
+        <div class="load-older">
+            <button class="btn btn-sm btn-outline-secondary"
+                    @onclick="OnLoadOlder"
+                    disabled="@IsLoading">
+                @(IsLoading ? "Loading..." : "↑ Load older messages")
+            </button>
+        </div>
+    }
+
+    @foreach (var message in Messages)
+    {
+        var msgId = message.Id;
+        ThreadSummaries.TryGetValue(msgId, out var summary);
+        var replyCount = summary?.ReplyCount ?? 0;
+
+        <MessageItem Message="message"
+                     ReplyCount="replyCount"
+                     OnReplyClicked="OnReplyClicked"
+                     OnReactionAdded="OnReactionAdded" />
+    }
+
+    @if (Messages.Count == 0 && !IsLoading)
+    {
+        <div class="no-messages">No messages yet. Start the conversation!</div>
+    }
+</div>
+
+@code {
+    [Parameter] public List<Message> Messages { get; set; } = new();
+    [Parameter] public Dictionary<int, ThreadSummary> ThreadSummaries { get; set; } = new();
+    [Parameter] public bool HasMore { get; set; }
+    [Parameter] public bool IsLoading { get; set; }
+    [Parameter] public EventCallback<int> OnReplyClicked { get; set; }
+    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReactionAdded { get; set; }
+    [Parameter] public EventCallback OnLoadOlder { get; set; }
+}
+

