@* Collapsible thread panel — shows root message, replies, and reply input *@

<div class="thread-panel">
    <div class="thread-header">
        <h6 class="mb-0">Thread</h6>
        <button class="btn-close btn-close-sm" aria-label="Close" @onclick="OnClose"></button>
    </div>

    <div class="thread-root-quote">
        <div class="quote-author">@RootMessage.Author</div>
        <div class="quote-content">@RootMessage.Content</div>
    </div>

    <div class="thread-replies">
        @if (Messages.Count == 0)
        {
            <div class="no-replies">No replies yet</div>
        }
        @foreach (var message in Messages)
        {
            <MessageItem Message="message"
                         ReplyCount="0"
                         OnReplyClicked="@((_) => { })"
                         OnReactionAdded="OnReactionAdded" />
        }
    </div>

    <MessageInput OnSend="OnReplySent" Placeholder="Reply..." ButtonText="Reply" />
</div>

@code {
    [Parameter, EditorRequired] public Message RootMessage { get; set; } = default!;
    [Parameter] public List<Message> Messages { get; set; } = new();
    [Parameter] public EventCallback OnClose { get; set; }
    [Parameter] public EventCallback<string> OnReplySent { get; set; }
    [Parameter] public EventCallback<(int MessageId, string Emoji)> OnReactionAdded { get; set; }
}

