+@page "/chat"
+@layout ChatLayout
+@rendermode InteractiveServer
+@inject IChatService ChatService
+
+<PageTitle>Chat</PageTitle>
+
+<div class="chat-container">
+    <ChannelSidebar Channels="channels"
+                    SelectedChannelId="selectedChannelId"
+                    OnChannelSelected="SelectChannel" />
+
+    <div class="main-area">
+        @if (selectedChannel is not null)
+        {
+            <div class="channel-header">
+                <h5 class="mb-0"># @selectedChannel.Name</h5>
+                <span class="channel-header-desc">@selectedChannel.Description</span>
+            </div>
+
+            <MessageList Messages="messages"
+                         ThreadSummaries="threadSummaries"
+                         HasMore="hasMoreMessages"
+                         IsLoading="isLoadingMessages"
+                         OnReplyClicked="OpenThread"
+                         OnReactionAdded="AddReaction"
+                         OnLoadOlder="LoadOlderMessages" />
+
+            <MessageInput OnSend="SendMessage"
+                          Placeholder="@($"Message #{selectedChannel.Name}")" />
+        }
+        else
+        {
+            <div class="empty-state">Select a channel to start chatting</div>
+        }
+    </div>
+
+    @if (isThreadOpen && threadRootMessage is not null)
+    {
+        <ThreadPanel RootMessage="threadRootMessage"
+                     Messages="threadMessages"
+                     OnClose="CloseThread"
+                     OnReplySent="SendReply"
+                     OnReactionAdded="AddReaction" />
+    }
+</div>
+
+@code {
+    private List<Channel> channels = new();
+    private Channel? selectedChannel;
+    private int selectedChannelId;
+
+    private List<Message> messages = new();
+    private Dictionary<int, ThreadSummary> threadSummaries = new();
+    private int messageSkip;
+    private bool hasMoreMessages = true;
+    private bool isLoadingMessages;
+    private const int PageSize = 50;
+
+    private Message? threadRootMessage;
+    private List<Message> threadMessages = new();
+    private bool isThreadOpen;
+
+    protected override async Task OnInitializedAsync()
+    {
+        channels = await ChatService.GetChannelsAsync();
+        if (channels.Count > 0)
+        {
+            await SelectChannel(channels[0]);
+        }
+    }
+
+    private async Task SelectChannel(Channel channel)
+    {
+        selectedChannel = channel;
+        selectedChannelId = channel.Id;
+        CloseThread();
+
+        messageSkip = 0;
+        hasMoreMessages = true;
+        messages = await ChatService.GetMessagesAsync(channel.Id, 0, PageSize);
+        messageSkip = messages.Count;
+        if (messages.Count < PageSize) hasMoreMessages = false;
+
+        BuildThreadSummaries();
+        await ChatService.MarkChannelReadAsync(channel.Id);
+
+        // Clear the unread badge locally
+        var idx = channels.FindIndex(c => c.Id == channel.Id);
+        if (idx >= 0)
+        {
+            channels[idx] = channel with { UnreadCount = 0 };
+        }
+    }
+
+    private async Task LoadOlderMessages()
+    {
+        if (!hasMoreMessages || isLoadingMessages || selectedChannel is null) return;
+
+        isLoadingMessages = true;
+        var older = await ChatService.GetMessagesAsync(selectedChannel.Id, messageSkip, PageSize);
+        if (older.Count < PageSize) hasMoreMessages = false;
+
+        messages.InsertRange(0, older);
+        messageSkip += older.Count;
+        BuildThreadSummaries();
+        isLoadingMessages = false;
+    }
+
+    private async Task SendMessage(string content)
+    {
+        if (selectedChannel is null) return;
+        var msg = await ChatService.SendMessageAsync(selectedChannel.Id, content, null);
+        messages.Add(msg);
+    }
+
+    private async Task OpenThread(int messageId)
+    {
+        threadRootMessage = messages.FirstOrDefault(m => m.Id == messageId);
+        if (threadRootMessage is null) return;
+
+        threadMessages = await ChatService.GetThreadAsync(messageId);
+
+        threadSummaries[messageId] = new ThreadSummary(
+            messageId,
+            threadMessages.Count,
+            threadMessages.Count > 0 ? threadMessages.Max(m => m.SentAt) : threadRootMessage.SentAt);
+
+        isThreadOpen = true;
+    }
+
+    private void CloseThread()
+    {
+        isThreadOpen = false;
+        threadRootMessage = null;
+        threadMessages = new();
+    }
+
+    private async Task SendReply(string content)
+    {
+        if (selectedChannel is null || threadRootMessage is null) return;
+
+        var reply = await ChatService.SendMessageAsync(selectedChannel.Id, content, threadRootMessage.Id);
+        threadMessages.Add(reply);
+
+        threadSummaries[threadRootMessage.Id] = new ThreadSummary(
+            threadRootMessage.Id,
+            threadMessages.Count,
+            reply.SentAt);
+    }
+
+    private async Task AddReaction((int MessageId, string Emoji) reaction)
+    {
+        await ChatService.AddReactionAsync(reaction.MessageId, reaction.Emoji);
+
+        // Update local state
+        var msg = messages.FirstOrDefault(m => m.Id == reaction.MessageId)
+               ?? threadMessages.FirstOrDefault(m => m.Id == reaction.MessageId);
+
+        if (msg is null) return;
+
+        var existing = msg.Reactions.FirstOrDefault(r => r.Emoji == reaction.Emoji);
+        if (existing is not null)
+        {
+            if (!existing.Users.Contains("You"))
+                existing.Users.Add("You");
+        }
+        else
+        {
+            msg.Reactions.Add(new Reaction(reaction.Emoji, new List<string> { "You" }));
+        }
+    }
+
+    private void BuildThreadSummaries()
+    {
+        threadSummaries.Clear();
+        var replies = messages
+            .Where(m => m.ReplyToId.HasValue)
+            .GroupBy(m => m.ReplyToId!.Value);
+
+        foreach (var group in replies)
+        {
+            threadSummaries[group.Key] = new ThreadSummary(
+                group.Key,
+                group.Count(),
+                group.Max(m => m.SentAt));
+        }
+    }
+}
+

