.chat-container {
    display: flex;
    height: 100vh;
    overflow: hidden;
    background: #fff;
}

.main-area {
    flex: 1;
    display: flex;
    flex-direction: column;
    min-width: 0;
    background: #fff;
}

.channel-header {
    padding: 12px 20px;
    border-bottom: 1px solid #dee2e6;
    background: #fff;
}

.channel-header h5 {
    font-weight: 700;
    font-size: 1.05rem;
}

.channel-header-desc {
    font-size: 0.82rem;
    color: #6c757d;
}

.empty-state {
    flex: 1;
    display: flex;
    align-items: center;
    justify-content: center;
    color: #adb5bd;
    font-size: 1rem;
}

